#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int A[n][m];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &A[i][j]);
        }
    }

    int p, q;
    scanf("%d %d", &p, &q);
    int B[p][q];
    for (int i = 0; i < p; i++) {
        for (int j = 0; j < q; j++) {
            scanf("%d", &B[i][j]);
        }
    }

    if (m != p) {
        printf("-1\n");
        return 0;
    }

    int C[n][q];

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < q; j++) {
            int sum = 0;
            for (int k = 0; k < m; k++) {
                sum += A[i][k] * B[k][j];
            }
            C[i][j] = sum;
        }
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < q; j++) {
            printf("%d ", C[i][j]);
        }
        printf("\n");
    }

    return 0;
}

